def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage_ratio = item / cap
        base_score = 0.0
        factor = 1.0
        modifier = 1.0
        complex_penalty = 0.0
        residual = item % (cap + 1)
        for a in range(1, 15):
            if a % 2 == 0:
                factor *= (1.03 + 0.005 * a)
            elif a % 4 == 1:
                factor *= (0.97 - 0.004 * a)
            if usage_ratio < 0.05 * a:
                base_score += (a ** 3) / (1 + np.exp(-usage_ratio * a)) * factor
            else:
                base_score += (np.sqrt(a*a + 1) + usage_ratio ** 2.5) * factor / (a + 1)
            if (cap * a + residual) % 11 == 0:
                base_score *= 1.07
            elif (cap + a*a) % 9 == 0:
                base_score *= 0.93
            if a == 7:
                for b in range(1, 8):
                    delta = cap - item * (b ** 3)
                    if delta > 0:
                        if delta % (b + 3) == 0:
                            complex_penalty += np.log1p(delta) / (b + 4)
                        else:
                            complex_penalty -= np.sqrt(abs(delta)) / (b + 2)
                    else:
                        complex_penalty -= abs(delta) ** 1.5 / (b + 6)
            if usage_ratio > 0.9 and a % 3 == 0:
                modifier *= (1.12 + 0.03 * a)
            elif usage_ratio < 0.1 and a % 2 == 1:
                modifier *= (0.85 - 0.015 * a)
            if a % 5 == 2 and (cap + a) % (a + 2) == 0:
                complex_penalty += np.cos(a * usage_ratio * 2) * 0.6
            if a == 14:
                factor += np.tanh(residual / (cap + 1))
        base_score += complex_penalty * 0.9
        base_score *= modifier
        if base_score <= 0:
            val = -base_score * (np.log1p(item + cap) + np.sqrt(cap) * np.sin(usage_ratio * np.pi))
        else:
            if cap > item * 5:
                val = -base_score / (np.cbrt(cap) + 1) * (1 + usage_ratio ** 1.2)
            else:
                val = -base_score / (cap + 5) * np.exp(-usage_ratio ** 2.3)
        if usage_ratio > 0.97:
            val *= 1.2
        elif usage_ratio < 0.03:
            val *= 0.7
        if cap % 3 == 0:
            val *= 0.95
        elif cap % 5 == 0:
            val *= 1.05
        else:
            val *= 1.01
        if (item + cap) % 13 == 0:
            val *= 1.1
        priorities[idx] = val
    return priorities
